<script setup lang="ts">import{onMounted,ref}from"vue";import{MapPin,Search,Hospital,Stethoscope,HeartPulse,Brain,Smile,Baby,Users,Accessibility,ChevronRight}from"lucide-vue-next";import{api,type Department,type Doctor}from"../api";import DoctorCard from"../components/DoctorCard.vue";const departments=ref<Department[]>([]),doctors=ref<Doctor[]>([]),query=ref("");const icons=[HeartPulse,Brain,Smile,Baby,Users,Accessibility];onMounted(async()=>{[departments.value,doctors.value]=await Promise.all([api.departments(),api.doctors()])});function search(){if(query.value)location.hash=`#/doctors?keyword=${encodeURIComponent(query.value)}`}</script><template><main class="home"><section class="home-top"><div class="brand-row"><b class="logo">安康挂号</b></div><div class="location-search"><button><MapPin/> 北京</button><div><Search/><input v-model="query" @keyup.enter="search" placeholder="搜医院、医生、科室"/></div></div><div class="find-grid"><router-link to="/hospitals"><span><Hospital/></span><div><b>找医院</b><small>全国优质医院</small></div></router-link><router-link to="/doctors"><span><Stethoscope/></span><div><b>找医生</b><small>专业医生覆盖</small></div></router-link></div></section><section class="home-card"><header><div><h2>预约挂号</h2><p>一站式挂号服务平台</p></div><router-link to="/doctors">全部科室 <ChevronRight/></router-link></header><div class="department-grid"><router-link v-for="(d,i) in departments.slice(0,10)" :key="d.id" :to="`/departments/${d.id}`"><component :is="icons[i%icons.length]"/><span>{{d.name}}</span></router-link></div></section><section class="specialty-center"><header><h2>专科中心</h2><p>专病就医指导</p></header><div><router-link v-for="d in departments.slice(0,6)" :key="d.id" :to="`/departments/${d.id}`"><b>{{d.name}}</b><small>守护{{d.name}}健康</small></router-link></div></section><section class="recommend"><header><h2>推荐医生</h2><p>真实号源 · 在线预约</p></header><DoctorCard v-for="d in doctors.slice(0,8)" :key="d.id" :doctor="d"/></section></main></template>
